const handleSubmit = async (e) => {

  e.preventDefault();

  try {

    // CHECK LOGIN

    const token =
      localStorage.getItem('token');

    if (!token) {

      alert(
        'Please login first'
      );

      return;
    }

    const formattedResume = {

      ...resume,

      skills:
        resume.skills.join(', '),

      education:
        resume.education.join('\n'),

      experience:
        resume.experience.join('\n'),

      projects:
        resume.projects.join('\n'),

      languages:
        resume.languages.join(', '),

      hobbies:
        resume.hobbies.join(', ')
    };

    const response =
      await ResumeService.saveResume(
        formattedResume
      );

    console.log(response.data);

    alert(
      'Resume Saved Successfully'
    );

    // CLEAR FORM

    setResume({

      fullName: '',
      email: '',
      phone: '',

      github: '',
      linkedin: '',
      portfolio: '',

      profileImage: '',

      summary: '',

      skills: [''],
      education: [''],
      experience: [''],
      projects: [''],
      languages: [''],
      hobbies: ['']
    });

  } catch (error) {

    console.log(
      'FULL ERROR:',
      error
    );

    console.log(
      'RESPONSE:',
      error.response
    );

    if (
      error.response &&
      error.response.status === 401
    ) {

      alert(
        'Unauthorized! Please login again.'
      );

    } else if (
      error.response &&
      error.response.status === 403
    ) {

      alert(
        'Access Denied'
      );

    } else if (
      error.response &&
      error.response.data
    ) {

      alert(
        error.response.data
      );

    } else {

      alert(
        'Error Saving Resume'
      );
    }
  }
};
